<?php namespace App\Repositories\Student;use App\Repositories\BaseRepository;use App\Models\Student\StudentMedicalRecord;use Illuminate\Database\Eloquent\Collection;use Illuminate\Pagination\LengthAwarePaginator;class StudentMedicalRecordRepository extends BaseRepository{    public function __construct(StudentMedicalRecord $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findByStudent(int $studentId): Collection    {        return $this->findByField('student_id', $studentId);    }    public function findByBloodGroup(string $bloodGroup): Collection    {        return $this->findByField('blood_group', $bloodGroup);    }    public function findByCondition(string $condition): Collection    {        return $this->query()->where('medical_conditions', 'like', "%{$condition}%")->get();    }    public function getAllergicStudents(): Collection    {        return $this->query()->whereNotNull('allergies')->where('allergies', '!=', '')->get();    }    public function getOnMedication(): Collection    {        return $this->query()->whereNotNull('current_medication')->where('current_medication', '!=', '')->get();    }    public function findByImmunizationStatus(string $status): Collection    {        return $this->findByField('immunization_status', $status);    }}